use tokio::sync::mpsc;
use std::time::Duration;

struct ConsensusResult {
    node_id: u32,
    success: bool,
}

async fn process_node(node_id: u32, tx: mpsc::Sender<ConsensusResult>)
    -> Result<(), Box<dyn std::error::Error>>
{
    tokio::time::sleep(Duration::from_millis(50 * node_id as u64)).await;
    let success = node_id % 3 != 0;
    let result = ConsensusResult { node_id, success };
    tx.send(result).await.ok();
    Ok(())
}

#[tokio::main]
async fn main()
{
    const NUM_NODES: u32 = 5;
    let (tx, mut rx) = mpsc::channel::<ConsensusResult>(10);
    let mut handles = Vec::new();

    for i in 1..=NUM_NODES {
        let tx_clone = tx.clone();
        handles.push(tokio::spawn(async move {
            match process_node(i, tx_clone).await {
                Ok(_) => (),
                Err(e) => eprintln!("Error processing node {}: {}", i, e)
            }
        }));
    }

    drop(tx); 

    let mut results_received = 0;
    while let Some(result) = rx.recv().await {
        println!("Received result for Node {}: Success={}", result.node_id, result.success);
        results_received += 1;
    }

    println!("nAll results collected. Total: {}", results_received);
    for handle in handles { 
        handle.await.ok();
    }
}

use tokio::task::JoinHandle;

struct TaskResult {
    id: u32,
    data: String,
}

async fn process_chunk(chunk_id: u32, input: &str) -> TaskResult {
    println!("Starting processing for chunk {}", chunk_id);
    tokio::time::sleep(std::time::Duration::from_millis(100 * (chunk_id % 3 + 1) as u64)).await;
    let processed = format!("Processed data for chunk {} using input: {}", chunk_id, input);
    println!("Finished processing for chunk {}", chunk_id);
    TaskResult { id: chunk_id, data: processed }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let inputs = vec!["A", "B", "C", "D"];
    let mut handles: Vec<JoinHandle<TaskResult>> = Vec::new();

    for (i, input) in inputs.iter().enumerate() {
        let chunk_id = (i + 1) as u32;
        let handle = tokio::spawn(process_chunk(chunk_id, input));
        handles.push(handle);
    }

    let mut results: Vec<TaskResult> = Vec::new();
    for handle in handles { 
        match handle.await {
            Ok(result) => results.push(result),
            Err(e) => eprintln!("A task failed to run properly: {}", e),
        }
    }

    println!("n--- All tasks completed ---");
    for result in results {
        println!("Result ID {}: {}", result.id, result.data);
    }

    Ok(())
}

use tokio::task::JoinHandle;

struct HealthCheck {
    name: String,
    check_duration_ms: u64,
}

impl HealthCheck {
    fn new(name: &str, duration: u64) -> Self {
        HealthCheck { name: name.to_string(), check_duration_ms: duration }
    }

    async fn run(&self) -> Result<String, String> {
        tokio::time::sleep(tokio::time::Duration::from_millis(self.check_duration_ms)).await;
        Ok(format!("\"{}\": \"ok\", \"last_seen\": \"{}\"", self.name, "some_timestamp"))
    }
}

async fn run_load_balancer_health_checks(checks: Vec<HealthCheck>) -> Result<String, String> {
    let mut handles: Vec<JoinHandle<Result<String, String>>> = Vec::new();

    for check in checks {
        let handle = tokio::spawn(async move { 
            check.run().await
        });
        handles.push(handle);
    }

    let mut results: Vec<Result<String, String>> = Vec::new();

    for handle in handles {
        match handle.await {
            Ok(inner_result) => results.push(inner_result),
            Err(e) => return Err(format!("Task panicked: {}", e)),
        }
    }

    if let Some(first_result) = results.into_iter().find(|r| r.is_ok()).map(|r| r.unwrap()) { 
        Ok(first_result)
    } else {
        Err("All health checks failed to report a status".to_string())
    }
}

#[tokio::main]
async fn main() {
    let checks = vec![
        HealthCheck::new("cpu", 100),
        HealthCheck::new("memory", 200),
        HealthCheck::new("network", 300),
    ];

    match run_load_balancer_health_checks(checks).await {
        Ok(result) => println!("Success: {}", result),
        Err(e) => eprintln!("Error: {}", e),
    }
}
